const calculator = {
  // Base costs and rates keyed by LOWERCASE analysisType
  PRICING: {
    basic:    { base: 500,  perGB: 10, perQuery: 0.005 },
    advanced: { base: 1000, perGB: 20, perQuery: 0.01  },
    custom:   { base: 2000, perGB: 40, perQuery: 0.02  }
  },

  calculate(inputs) {
    const validation = this.validate(inputs);
    if (validation.error) {
      return { error: validation.error };
    }

    const volume = inputs.param1;      // already validated as number > 0
    const queries = inputs.param2;     // validated as number >= 0
    const type = inputs.param3;        // normalized to lowercase basic/advanced/custom
    const realTime = inputs.param4;    // boolean

    const pricing = this.PRICING[type];
    const baseCost = pricing.base;
    const volumeCost = volume * pricing.perGB;
    const queryCost = queries * pricing.perQuery;
    const subtotal = baseCost + volumeCost + queryCost;
    const realTimeMultiplier = realTime ? 1.25 : 1;
    const realTimeSurcharge = realTime ? subtotal * 0.25 : 0;
    const total = Math.round(subtotal * realTimeMultiplier * 100) / 100; // round to 2 decimals

    return {
      total: total,
      breakdown: {
        baseCost: baseCost,
        volumeCost: Math.round(volumeCost * 100) / 100,
        queryCost: Math.round(queryCost * 100) / 100,
        realTimeSurcharge: Math.round(realTimeSurcharge * 100) / 100,
        total: total
      }
    };
  },

  validate(inputs) {
    const errors = [];
    // param1 validation
    if (typeof inputs.param1 !== 'number' || isNaN(inputs.param1)) {
      errors.push("Data Volume (GB) must be a number");
    } else if (inputs.param1 <= 0) {
      errors.push("Data Volume (GB) must be greater than 0");
    }
    // param2 validation
    if (typeof inputs.param2 !== 'number' || isNaN(inputs.param2)) {
      errors.push("Monthly Queries must be a number");
    } else if (inputs.param2 < 0) {
      errors.push("Monthly Queries must be 0 or greater");
    }
    // param3 validation (normalize case and trim)
    const rawType = inputs.param3 !== undefined ? String(inputs.param3).trim().toLowerCase() : null;
    if (rawType === null || rawType === '') {
      errors.push("Analysis type is required");
    } else if (!['basic','advanced','custom'].includes(rawType)) {
      errors.push("Invalid analysis type. Must be one of: basic, advanced, custom");
    }
    // param4 validation (boolean)
    if (typeof inputs.param4 !== 'boolean') {
      errors.push("Real-Time Processing must be a boolean (true or false)");
    }
    if (errors.length > 0) {
      return { error: errors.join('. ') };
    }
    return {};
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  { name:'param1', label:'Data Volume (GB)', type:'number', placeholder:'e.g. 50' },
  { name:'param2', label:'Monthly Queries', type:'number', placeholder:'e.g. 10000' },
  { name:'param3', label:'Analysis Type', type:'select', options:[['basic','🔍 Basic'],['advanced','🚀 Advanced'],['custom','✨ Custom']] },
  { name:'param4', label:'Real-Time Processing', type:'checkbox' }
];
